import React from 'react';
import { FiActivity } from 'react-icons/fi';

const GapForecast: React.FC = () => {
  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="bg-slate-900/60 backdrop-blur-md p-8 rounded-2xl shadow-sm border border-slate-700/50">
        <h3 className="text-2xl font-bold text-white mb-6 flex items-center gap-2">
          <FiActivity className="text-red-500" /> Skill Gap Forecast
        </h3>
        <div className="space-y-4">
          {[
            { name: 'LLM Fine-tuning', gap: 65, status: 'Critical' },
            { name: 'Vector Databases', gap: 40, status: 'Moderate' },
            { name: 'MLOps Automation', gap: 15, status: 'Low' },
          ].map((item, i) => (
            <div key={i} className="p-4 bg-slate-800/50 rounded-xl">
              <div className="flex justify-between items-center mb-2">
                <span className="font-bold text-slate-100">{item.name}</span>
                <span className={`px-2 py-1 rounded-md text-xs font-bold ${
                  item.status === 'Critical' ? 'bg-red-100 text-red-600' : 
                  item.status === 'Moderate' ? 'bg-yellow-100 text-yellow-600' : 'bg-green-100 text-green-600'
                }`}>{item.status}</span>
              </div>
              <div className="w-full bg-slate-700 h-2 rounded-full overflow-hidden">
                <div className={`h-full ${
                  item.status === 'Critical' ? 'bg-red-500' : 
                  item.status === 'Moderate' ? 'bg-yellow-500' : 'bg-green-500'
                }`} style={{ width: `${item.gap}%` }}></div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default GapForecast;
